	}

	if nesting := int(m["max_nesting_depth"]); nesting > 3 {
		penalty := float64(nesting-3) * 0.05
		if v, ok := scores[domain.DimReadability]; ok {
			scores[domain.DimReadability] = max(0, v-penalty)
		} else {
