func TestScore_GenericTier_ReturnsNil(t *testing.T) {
	result := Score("generic-lang", nil, policy.EvaluationResult{})
	if result != nil {
		t.Errorf("expected nil for generic tier language, got %v", result)
	}
}

func TestScore_NonGenericTier_ReturnsScores(t *testing.T) {
	// A known Go-like language should not be generic tier
	result := Score("go", nil, policy.EvaluationResult{})
	if result == nil {
		t.Error("expected non-nil scores for non-generic tier language")
	}
}

func TestScoreFromMetrics_ComplexityZero_GenericTier_SkipsBoost(t *testing.T) {
	scores := make(domain.DimensionScores)
	ev := domain.Evidence{
		Kind: domain.EvidenceKindMetrics,
		Metrics: map[string]float64{
			"complexity": 0,
		},
	}
	scoreFromMetrics("generic-lang", ev, scores)
	if _, ok := scores[domain.DimMaintainability]; ok {
		t.Errorf("expected no maintainability boost for complexity==0 in generic tier, got %v", scores[domain.DimMaintainability])
	}
}

func TestScoreFromMetrics_ComplexityZero_NonGenericTier_GetsBoost(t *testing.T) {
	scores := make(domain.DimensionScores)
	ev := domain.Evidence{
		Kind: domain.EvidenceKindMetrics,
		Metrics: map[string]float64{
			"complexity": 0,
		},
	}
	scoreFromMetrics("go", ev, scores)
	if v, ok := scores[domain.DimMaintainability]; !ok || v != 0.95 {
		t.Errorf("expected maintainability 0.95 for complexity==0 in non-generic tier, got %v", scores[domain.DimMaintainability])
	}
}

func TestScore_Violations_DoNotInjectNewDimensions(t *testing.T) {
	ev := []domain.Evidence{}
	evalResult := policy.EvaluationResult{
		Violations: []domain.Violation{
			{Dimension: domain.DimMaintainability, Severity: domain.SeverityWarning},
		},
	}
	result := Score("go", ev, evalResult)
	if _, ok := result[domain.DimMaintainability]; ok {
		t.Errorf("expected no new dimension injection from violations alone, but maintainability was present: %v", result[domain.DimMaintainability])
	}
}

func TestScore_Violations_PenalizeExistingDimensions(t *testing.T) {
	ev := []domain.Evidence{{
		Kind:   domain.EvidenceKindMetrics,
		Passed: true,
		Metrics: map[string]float64{
			"complexity": 3,
		},
	}}
	evalResult := policy.EvaluationResult{
		Violations: []domain.Violation{
			{Dimension: domain.DimMaintainability, Severity: domain.SeverityWarning},
		},
	}
	result := Score("go", ev, evalResult)
	v, ok := result[domain.DimMaintainability]
	if !ok {
		t.Fatal("expected maintainability to be present from evidence")
	}
	// complexity 3 → boost to 0.95, then warning penalty -0.1 → 0.85
	if v != 0.85 {
		t.Errorf("expected maintainability 0.85 after boost+penalty, got %v", v)
	}
}

func TestScorer_TierGenericReturnsNil(t *testing.T) {
	ev := []domain.Evidence{{
		Kind:   domain.EvidenceKindMetrics,
		Passed: true,
		Metrics: map[string]float64{
			"complexity": 3,
		},
	}}
	evalResult := policy.EvaluationResult{
		Violations: []domain.Violation{
			{Dimension: domain.DimMaintainability, Severity: domain.SeverityWarning},
		},
	}
	result := Score("swift", ev, evalResult)
	if result != nil {
		t.Errorf("expected nil for generic tier language 'swift', got %v", result)
	}
}

func TestScorer_ZeroComplexityTierGenericNoMaintainabilityBoost(t *testing.T) {
	ev := []domain.Evidence{{
		Kind: domain.EvidenceKindMetrics,
		Metrics: map[string]float64{
			"complexity": 0,
		},
	}}
	result := Score("swift", ev, policy.EvaluationResult{})
	// For generic tier, complexity==0 means "unmeasured" — no boost.
	// Since Score returns nil for generic tier, maintainability cannot be present.
	// Either the result is nil (whole map absent) or maintainability is absent from it.
	if result != nil {
		if v, ok := result[domain.DimMaintainability]; ok && v == 0.95 {
			t.Errorf("expected no maintainability boost for complexity==0 in generic tier, got 0.95")
		}
	}
}

func TestScorer_ViolationOnAbsentDimensionDoesNotInject(t *testing.T) {
	ev := []domain.Evidence{{
		Kind:   domain.EvidenceKindMetrics,
		Passed: true,
		Metrics: map[string]float64{
			"complexity": 3,
		},
	}}
	evalResult := policy.EvaluationResult{
		Violations: []domain.Violation{
			{Dimension: domain.DimSecurity, Severity: domain.SeverityWarning},
		},
	}
	result := Score("go", ev, evalResult)
	// Violations on dimensions without evidence must not inject them.
	if _, ok := result[domain.DimSecurity]; ok {
		t.Errorf("expected security dimension to be absent (no evidence), but it was injected: %v", result[domain.DimSecurity])
	}
}

